import React, { useState } from 'react';

const App = () => {
  const [channels, setChannels] = useState(['Channel 1', 'Channel 2', 'Channel 3']);
  const [messages, setMessages] = useState({ 'Channel 1': ['Message 1', 'Message 2', 'Message 3'], 'Channel 2': ['Message 4', 'Message 5', 'Message 6'], 'Channel 3': ['Message 7', 'Message 8', 'Message 9'] });
  const [filteredMessages, setFilteredMessages] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');

  const handleSearch = (e) => {
    const term = e.target.value.toLowerCase();
    const filtered = Object.keys(messages).reduce((acc, channel) => {
      return acc.concat(messages[channel].filter((message) => message.toLowerCase().includes(term)));
    }, []);
    setFilteredMessages(filtered);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 w-[360px] m-auto">
        <div className="bg-[#C06C88] p-2 w-full mb-4">
          <input type="text" placeholder="Search" value={searchTerm} onChange={handleSearch} className="w-full py-2 pl-10 text-sm text-white focus:outline-none focus:ring-2 focus:ring-white"/>
        </div>
        <div className="bg-[#411C56] p-2 w-full mb-4">
          <button onClick={() => setFilteredMessages([])}>Clear</button>
        </div>
        <div className="bg-[#B7D7CD] p-2 w-full mb-4">
          <select onChange={(e) => setFilteredMessages(messages[e.target.value])} className="w-full py-2 pl-10 text-sm text-white focus:outline-none focus:ring-2 focus:ring-white">
            {channels.map((channel, index) => (
              <option key={index} value={channel}>{channel}</option>
            ))}
          </select>
        </div>
        <div className="bg-[#C06C88] p-2 w-full mb-4">
          {filteredMessages.map((message, index) => (
            <p key={index}>{message} - <img src={require('./avatar.png')} width={30} height={30}/></p>
          ))}
        </div>
      </div>
    </div>
  );
};

export default App;
